    "restoreOnDisable": true,
    "maxSkillifyConcurrency": 3,
    "contextSettings": {
      "decisionRecentContextCharLimit": 2,
      "decisionPreviousPlotCharLimit": 1,
      "decisionWorldbookContentPreviewLimit": 1000,
      "decisionWorldbookCandidateLimit": 100,
      "skillifyContentPreviewLimit": 1200,
      "skillifyMaxEntries": 100,
      "plotWorldbookScanMessageLimit": 3,
      "agentAiMaxRetries": 2,
      "greenlightMinTkBudget": 20000,
      "greenlightMaxTkBudget": 80000
    },
    "contextSettingsConfigured": false,
    "agentDecisionPromptSegments": [
      {
        "role": "system",
        "content": "你是 SillyTavern 插件 SP·数据库的前置控制 Agent。\n你必须基于用户输入、最近上下文、推进任务 Skill、世界书 Skill 元数据，决定本轮剧情推进任务和世界书绿灯条目。\n只返回严格 JSON 对象，不要 Markdown，不要解释。\nJSON 结构：{{agent.outputSchemaJson}}\ntaskId 必须来自候选任务。候选任务只包含需要 Agent 判断的任务；未出现的任务会按用户设定顺序执行，不要为它们生成 taskPlan。\n世界书绿灯按候选世界书 index 编号输出，禁止输出长篇解释；reason 每个编号只写一句话。\n候选世界书条目中的 tokenEstimate/tk 表示该条目预计消耗的 Token 数量，不是触发关键词。\nplotGreenlights 只控制剧情推进任务，且每个 taskId 的条目必须匹配该任务 description/triggerWhen；finalGenerationGreenlights 只控制正文生成。当前不要为填表阶段安排世界书绿灯条目。\n每个通道和每个任务都要按绿灯 Token 预算选择条目：在相关条目足够时，必须尽可能超过最小 Token 预算；如果相关候选条目总 Token 不足最小预算，则选择全部相关候选；任何情况下都不得超过最大 Token 预算。\n不要为了凑最小 Token 预算选择与任务或正文生成无关的条目。",
        "deletable": false
      },
      {
        "role": "user",
        "content": "用户输入：\n{{agent.userMessage}}\n\n最近上下文（含用户楼层中的剧情推进记录）：\n{{agent.recentContext}}\n\n候选推进任务 JSON：\n{{agent.tasksJson}}\n\n候选世界书条目 JSON：\n{{agent.worldbookEntriesJson}}\n\n通道条目上限 JSON：\n{{agent.maxEntriesPerChannelJson}}\n\n绿灯 Token 预算 JSON：\n{{agent.greenlightTkBudgetJson}}",
        "deletable": true
      }
    ],
    "agentSkillifyPromptSegments": [
      {
        "role": "system",
        "content": "你是 SillyTavern 世界书条目的 Skill 元数据生成器。根据条目名称、关键词、条目正文和条目 TK，生成用于 Agent 判断是否触发该条目的描述、触发时机与 tk 数值。只返回严格 JSON 对象，不要 Markdown，不要解释。JSON 结构：{{agent.skillify.outputSchemaJson}}",
        "deletable": false
      },
      {
        "role": "user",
        "content": "世界书: {{agent.skillify.bookName}}\n条目 uid: {{agent.skillify.uid}}\n条目名称/备注: {{agent.skillify.comment}}\n关键词: {{agent.skillify.keysText}}\n条目 TK: {{agent.skillify.tk}}\n条目正文:\n{{agent.skillify.content}}\n已有 Skill 元数据 JSON: {{agent.skillify.existingSkillMetaJson}}",
        "deletable": true
      }
    ],
    "maxEntriesPerChannel": {
      "plot": 20,
      "tableFill": 20,
      "finalGeneration": 20
    }
  },
